mapper.select:
with temp as ( select hf.*, ha.name, ha.suffix, ha.`path`, ha.update_name, ROW_NUMBER() OVER (ORDER BY hf.update_time DESC) AS RowNum from hlvr_file hf left join hlvr_attachment ha on hf.id =ha.business_id where ha.del_flag =0 and hf.del_flag =0
and hf.asset_type =#{param.assetType}
) SELECT * FROM temp WHERE RowNum BETWEEN ((#{current} -1) * #{size} + 1 ) AND (#{current} * #{size})
